import React from "react";
import Post1 from "../../../assets/images/DashboardImgs/post-1.png";
import ApiRequest from "../../../Services/ApiRequest";
import { toasterAlert } from "../../../Helpers/Functions";
import { Editor } from "react-draft-wysiwyg";
import { ContentState, convertToRaw, EditorState, convertFromHTML } from 'draft-js'
import "react-draft-wysiwyg/dist/react-draft-wysiwyg.css";
import draftToHtml from 'draftjs-to-html'
import Redirect from "../../../Utils/history";
import { Link } from "react-router-dom";


class ThirdTab extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            errors: {},
            editorState: EditorState.createEmpty(),
            readOnly:false
        };
        this.handleChange = this.handleChange.bind(this);
        this.handleSubmit = this.handleSubmit.bind(this);

    }
    componentDidUpdate(prevProps, prevState) {
        if (this.props.postInfo !== prevProps.postInfo) {
            this.setState({
                editorState:EditorState.createWithContent(
                    ContentState.createFromBlockArray(
                        convertFromHTML(this.props.postInfo?.jobLists?.[0]?.details?.description)
                    )
                ),
            })
        }
    }

    onEditorStateChange = (editorState) => {
        if(!this.state.readOnly){
            this.setState({
                editorState,
                description: draftToHtml(
                    convertToRaw(editorState.getCurrentContent())
                )
            });
        }
    }
    static getDerivedStateFromProps(props, state) {
        if (props.postInfo !== state.postInfo) {
            return {
                postInfo: props.postInfo,
                aditional_description: props.postInfo?.jobLists?.[0]?.details?.aditional_description,
                compensation: props.postInfo?.jobLists?.[0]?.details?.compensation,
                contract_type: props.postInfo?.jobLists?.[0]?.details?.contract_type,
                description: props.postInfo?.jobLists?.[0]?.details?.description,
                end_price: props.postInfo?.jobLists?.[0]?.details?.end_price,
                salary_type: props.postInfo?.jobLists?.[0]?.details?.salary_type,
                start_date: props.postInfo?.jobLists?.[0]?.details?.start_date,
                start_price: props.postInfo?.jobLists?.[0]?.details?.start_price,
                type_of_employment: props.postInfo?.jobLists?.[0]?.details?.type_of_employment,
                readOnly: props.readOnly
            };
        }
        return null; // No change to state
    }
    handleChange(event) {
        if(!this.state.readOnly){
            const { name, value } = event.target;
            this.setState({ [name]: value })
        }
    }

    handleSubmit = async (event) => {

        event.preventDefault();
        if(!this.state.readOnly){
            const { type_of_employment, contract_type, start_date, compensation, start_price, end_price, salary_type, description, aditional_description } = this.state;
            let { typeEmploymentError, contractTypeError, startDateError, compensationError, startPriceError, endPriceError, salaryTypeError, descriptionError, aditionalDesError } = '';
            if (!type_of_employment) {
                typeEmploymentError = "This field is required";
            }
            if (!contract_type) {
                contractTypeError = "This field is required";
            }
            if (!start_date) {
                startDateError = "This field is required";
            }
            if (!compensation) {
                compensationError = "This field is required";
            }
            if (!start_price) {
                startPriceError = "This field is required";
            }
            if (!end_price) {
                endPriceError = "This field is required";
            }
            if (!salary_type) {
                salaryTypeError = "This field is required";
            }
            if (!description) {
                descriptionError = "This field is required";
            }
            if (!aditional_description) {
                aditionalDesError = "This field is required";
            }
            this.setState({
                errors: {
                    typeEmploymentError: typeEmploymentError,
                    contractTypeError: contractTypeError,
                    startDateError: startDateError,
                    compensationError: compensationError,
                    startPriceError: startPriceError,
                    endPriceError: endPriceError,
                    salaryTypeError: salaryTypeError,
                    descriptionError: descriptionError,
                    aditionalDesError: aditionalDesError,
                }
            })
    
            if (typeEmploymentError || contractTypeError || startDateError || compensationError || startPriceError || endPriceError | salaryTypeError || descriptionError || aditionalDesError) {
                return;
            }
    
            const response = await ApiRequest.putRequest(`/jobPostDetails/${this.state.postInfo?.jobLists?.[0]?.details?.id}`, { type_of_employment, contract_type, start_date, start_price, end_price, compensation, salary_type, description, aditional_description })
            if (response && response.status === 200) {
                toasterAlert('success', "Job Post Successfully updated")
                Redirect.push('/JobPosting')
    
            } else {
                toasterAlert('error', 'Something went wrong please try again')
            }
        }else{
            Redirect.push('/JobPosting')
        }

    }
    render() {
        const { editorState } = this.state;
        console.log(this.state.postInfo)
        return (
            <div className={`row mar-width-0 postBodyWrap ${this.props.className}`}>
                <div className="container">
                    <div className="row mar-width-0 postWrap">
                        <div className="col-md-6 align-self-center pl-50">
                            <h3>Job Details</h3>
                        </div>
                        <div className="col-md-6 text-center pl-50">
                            <img src={Post1} alt="" />
                        </div>
                    </div>
                    <form className="w-100 form-wrap" onSubmit={this.handleSubmit}>

                        <div className="row mar-width-0 postDetails">
                            <div className="col-md-12">
                                <h5>Job Details</h5>
                            </div>
                            <div className="col-md-12 mb-3">
                                <div className="row job-d">
                                    <div className="col-md-12">
                                        <div className="job-details">
                                            <span className="job-d-title">Job title: </span><p className="m-0"> {this.state?.postInfo?.jobLists?.[0]?.job_title}</p>
                                        </div>
                                    </div>
                                    <div className="col-md-12">
                                        <div className="job-details">
                                            <span className="job-d-title">Job company name: </span><p className="m-0"> {this.state?.postInfo?.jobLists?.[0]?.company_name}</p>
                                        </div>
                                    </div>
                                    <div className="col-md-12">
                                        <div className="job-details">
                                            <span className="job-d-title">Job location: </span><p className="m-0"> {this.state?.postInfo?.jobLists?.[0]?.city?.name}, {this.state?.postInfo?.jobLists?.[0]?.country?.name}</p>
                                        </div>
                                    </div>
                                </div>

                            </div>
                            <div className="col-md-12 mb-3">
                                <div className="form-group mb-0">
                                    <label htmlFor="exampleInputEmail1">What type of employment is it?</label>
                                    <select className="form-select" name="type_of_employment" onChange={this.handleChange} value={this.state.type_of_employment} aria-label="Default select example">
                                        <option selected></option>
                                        <option value="1">Monthly</option>
                                        <option value="2">Yearly</option>
                                    </select>
                                    <span className="error">{this.state.errors.typeEmploymentError}</span>

                                </div>
                            </div>
                            <div className="col-md-12 mb-2 radio-">
                                <label>
                                    What contract type is it?
                                </label><br />
                                <label className="custom-control fill-checkbox">
                                    <input type="radio" className="fill-control-input" name="contract_type" value="1" onChange={this.handleChange} checked={this.state.contract_type ==1?true:''} />
                                    <span className="fill-control-indicator"></span>
                                    <span className="f-f2"> Temporary</span>
                                </label>
                                <label className="custom-control fill-checkbox">
                                    <input type="radio" className="fill-control-input" name="contract_type" value="2" onChange={this.handleChange} checked={this.state.contract_type ==2?true:''}/>
                                    <span className="fill-control-indicator"></span>
                                    <span className="f-f2"> New-Grad</span>
                                </label>
                                <label className="custom-control fill-checkbox">
                                    <input type="radio" className="fill-control-input" name="contract_type" value="3" onChange={this.handleChange} checked={this.state.contract_type ==3?true:''}/>
                                    <span className="fill-control-indicator"></span>
                                    <span className="f-f2"> Contract</span>
                                </label>
                                <label className="custom-control fill-checkbox">
                                    <input type="radio" className="fill-control-input" name="contract_type" value="4" onChange={this.handleChange} checked={this.state.contract_type ==4?true:''}/>
                                    <span className="fill-control-indicator"></span>
                                    <span className="f-f2"> Internship</span>
                                </label>
                                <label className="custom-control fill-checkbox">
                                    <input type="radio" className="fill-control-input" name="contract_type" value="5" onChange={this.handleChange} checked={this.state.contract_type ==5?true:''}/>
                                    <span className="fill-control-indicator"></span>
                                    <span className="f-f2"> commission</span>
                                </label>

                            </div>

                            <div className="col-md-12 mb-2 radio-">
                                <label>
                                    Is there planned start date for this job?
                                </label>
                                <p>
                                    <input type="radio" id="test4" name="start_date" value="1" onChange={this.handleChange} checked={this.state.start_date ==1?true:''}/>
                                    <label htmlFor="test4">Yes</label>
                                </p>
                                <p className="mt-2">
                                    <input type="radio" id="test5" name="start_date" value="2" onChange={this.handleChange} checked={this.state.start_date ==2?true:''}/>
                                    <label htmlFor="test5">No</label>
                                </p>


                            </div>


                        </div>
                        <div className="row mar-width-0 postDetails">
                            <div className="col-md-12">
                                <h5>Salary</h5>
                            </div>
                            <div className="col-md-12 row mb-3">
                                <div className="col-md-5">
                                    <label htmlFor="exampleInputEmail1">Compensation</label>
                                    <select className="form-select" name="compensation" onChange={this.handleChange} value={this.state.compensation} aria-label="Default select example">
                                        <option selected></option>
                                        <option value="1">Range</option>
                                    </select>
                                    <span className="error">{this.state.errors.compensationError}</span>
                                </div>

                            </div>
                            <div className="col-md-5">
                                <input type="number" name="start_price" className="form-control" id="exampleInputEmail1"
                                    value={this.state.start_price}
                                    onChange={this.handleChange}
                                />
                            </div>
                            <div className="col-md-5">
                                <input type="number" name="end_price" className="form-control" id="exampleInputEmail1"
                                    value={this.state.end_price}
                                    onChange={this.handleChange}
                                />
                            </div>

                            <div className="col-md-2 mb-3">
                                <select className="form-select" name="salary_type" onChange={this.handleChange} value={this.state.salary_type} aria-label="Default select example">
                                    <option selected></option>
                                    <option value="1">Monthly</option>
                                    <option value="2">Yearly</option>
                                </select>
                                <span className="error">{this.state.errors.salaryTypeError}</span>

                            </div>

                        </div>
                        <div className="row mar-width-0 postDetails">
                            <div className="col-md-12">
                                <h5>Salary</h5>
                            </div>
                            <div className="col-md-12 mb-3">
                                <label htmlFor="exampleInputEmail1">Describe the responsibility of this job, required work experience, skills, or education.</label>
                                <Editor
                                    editorState={editorState}
                                    wrapperClassName="editor-wrapper"
                                    editorClassName="editor-area"
                                    toolbarClassName="editor-toolbar"
                                    toolbar={{
                                        options: ['inline', 'link', 'list', 'textAlign', 'embedded'],
                                        inline: {
                                            options: ['bold', 'italic', 'strikethrough']
                                        },
                                        link: {
                                            options: ['link']
                                        }
                                    }}
                                    onEditorStateChange={this.onEditorStateChange}
                                />
                                <span className="error">{this.state.errors.descriptionError}</span>


                            </div>
                            <div className="col-md-12">
                                <h5>Are you taking any aditional COVID-19 precautions?</h5>
                            </div>
                            <div className="col-md-12 mb-3">
                                <label htmlFor="exampleInputEmail1">Let Job seekers know how you're responding to COVID-19.</label>
                                <textarea className="form-control"
                                    id="exampleFormControlTextarea1"
                                    name="aditional_description"
                                    onChange={this.handleChange}
                                    rows={4} value={this.state.aditional_description}>{this.state.aditional_description}</textarea>
                                <span className="error">{this.state.errors.aditionalDesError}</span>


                            </div>
                            <div className="row mar-width-0 mt-5">
                                <div className="col-md-6">
                                    <Link to="/JobPosting" className="btn btn-back">Back</Link>

                                </div>
                                <div className="col-md-6 text-right">
                                    <button type="submit" className="btn btn-continue">Continue</button>
                                </div>
                            </div>

                        </div>
                    </form>
                </div>
            </div>
        )
    }
}
export default ThirdTab;